BEGIN
  // Each process has send_buffer of size P × msg_size
  // Process i sends send_buffer[i*msg_size:(i+1)*msg_size] to process i

  // Initialize send buffers with unique data
  FOR i = 0 TO P-1 DO
    send_buffer[i*msg_size:(i+1)*msg_size] = generate_my_data_for_process(i)
  END FOR

  // Perform all-to-all using MPI_Alltoall
  MPI_Alltoall(send_buffer, msg_size, MPI_DOUBLE,
               recv_buffer, msg_size, MPI_DOUBLE, comm)

  // After call, recv_buffer[j*msg_size:(j+1)*msg_size] contains
  // the message received from process j

  // Verification: each process should have P unique messages
  FOR j = 0 TO P-1 DO
    IF recv_buffer[j*msg_size] != expected_from_process(j) THEN
      PRINT "Error: unexpected message from process", j
    END IF
  END FOR
END
